args.sparql:
SELECT ?person ?birthDate ?personLabel WHERE {
  ?person wdt:P31 wd:Q5 .
  ?person wdt:P106 wd:Q13474373 .
  ?person wdt:P569 ?birthDate .
  FILTER NOT EXISTS { ?person wdt:P570 [] }
  OPTIONAL { ?person rdfs:label ?personLabel . FILTER(LANG(?personLabel) = "en") }
}
ORDER BY ?birthDate
LIMIT 1

SELECT ?person ?personLabel (YEAR(?birthDate) AS ?birthYear)
WHERE {
  ?person wdt:P31 wd:Q5 .
  ?person wdt:P106/wdt:P279* wd:Q12839983 .
  ?person wdt:P569 ?birthDate .
  FILTER NOT EXISTS { ?person wdt:P570 [] }
  OPTIONAL { ?person rdfs:label ?personLabel . FILTER(LANG(?personLabel) = "en") }
}
ORDER BY ASC(?birthYear)
LIMIT 1
